const campaigns = $input.first().json.data || [];
return campaigns.map(campaign => {
  const insights  = campaign.insights?.data?.[0] || {};
  const actions   = insights.actions || [];
  const leads     = actions.find(a => a.action_type === 'lead')?.value || 0;
  const purchases = actions.find(a => a.action_type === 'purchase')?.value || 0;
  return {
    json: {
      plataforma:      'meta',
      campanha_id:     campaign.id,
      campanha_nome:   campaign.name,
      data_referencia: new Date(Date.now() - 86400000).toISOString().split('T')[0],
      spend:           parseFloat(insights.spend || 0),
      impressions:     parseInt(insights.impressions || 0),
      clicks:          parseInt(insights.clicks || 0),
      leads:           parseInt(leads),
      conversoes:      parseInt(purchases)
    }
  };
});

const items = $input.all();
const spend_total  = items.reduce((s, i) => s + (parseFloat(i.json.spend)  || 0), 0);
const leads_total  = items.reduce((s, i) => s + (parseInt(i.json.leads)    || 0), 0);
const cpl = leads_total > 0 ? (spend_total / leads_total).toFixed(2) : null;
return [{ json: { meta_spend_total: spend_total.toFixed(2), meta_leads_total: leads_total, meta_cpl: cpl } }];

const rows = $input.first().json.results || [];
return rows.map(row => ({
  json: {
    plataforma:      'google',
    campanha_id:     row.campaign.id,
    campanha_nome:   row.campaign.name,
    data_referencia: new Date(Date.now() - 86400000).toISOString().split('T')[0],
    spend:           parseFloat((row.metrics.costMicros || 0) / 1000000),
    impressions:     parseInt(row.metrics.impressions  || 0),
    clicks:          parseInt(row.metrics.clicks       || 0),
    leads:           0,
    conversoes:      parseInt(row.metrics.conversions  || 0)
  }
}));

const items = $input.all();
const spend_total     = items.reduce((s, i) => s + (parseFloat(i.json.spend)     || 0), 0);
const conversoes_total = items.reduce((s, i) => s + (parseInt(i.json.conversoes) || 0), 0);
const cpa = conversoes_total > 0 ? (spend_total / conversoes_total).toFixed(2) : null;
return [{ json: { google_spend_total: spend_total.toFixed(2), google_conversoes_total: conversoes_total, google_cpa: cpa } }];
